是的，从Qt5.1版本开始，Qt官方推荐使用QNetworkAccessManager和QNetworkReply来实现FTP和其他网络协议的访问。

以下是使用QNetworkAccessManager和QNetworkReply实现FTP下载的示例代码：

```cpp
QUrl url("ftp://example.com/path/to/file.txt");
QNetworkRequest request(url);
QNetworkAccessManager manager;
QNetworkReply *reply = manager.get(request);

// 监听reply的finished()信号
connect(reply, &QNetworkReply::finished, [reply]{
    QString fileName = reply->url().fileName();
    QFile file(fileName);
    if (file.open(QIODevice::WriteOnly)) {
        file.write(reply->readAll());
        file.close();
        qDebug() << "Downloaded" << fileName;
    }
    reply->deleteLater();
});

// 监听reply的downloadProgress()信号
connect(reply, &QNetworkReply::downloadProgress, [](qint64 bytesReceived, qint64 bytesTotal){
    if (bytesTotal > 0) {
        int progress = (int)(bytesReceived * 100 / bytesTotal);
        qDebug() << "Progress:" << progress << "%";
    }
});
```

在这个示例中，使用QUrl和QNetworkRequest构建FTP请求，然后使用QNetworkAccessManager的get()方法获取QNetworkReply对象。在QNetworkReply对象的finished()信号中，读取服务器返回的数据，并将其写入到本地文件中。在downloadProgress()信号中，可以监听下载进度并进行显示。最后，别忘了在下载完成后及时调用reply的deleteLater()方法释放内存。

需要注意的是，在使用QNetworkAccessManager和QNetworkReply进行FTP下载时，需要在.pro文件中添加如下配置：

```qmake
QT += network
CONFIG += network
```

可以将上述代码封装成一个ftpClient类，并添加支持多文件下载批量下载的功能，示例代码如下：

ftpclient.h 文件：

```cpp
#ifndef FTPCLIENT_H
#define FTPCLIENT_H

#include <QObject>
#include <QNetworkAccessManager>
#include <QNetworkReply>

class FtpClient : public QObject
{
    Q_OBJECT
public:
    explicit FtpClient(QObject *parent = nullptr);
    void downloadFiles(const QStringList &urls);

private:
    QNetworkAccessManager m_manager;
    QList<QNetworkReply*> m_replies;

private slots:
    void onDownloadProgress(qint64 bytesReceived, qint64 bytesTotal);
    void onDownloadFinished();
};

#endif // FTPCLIENT_H
```

ftpclient.cpp 文件：

```cpp
#include "ftpclient.h"
#include <QUrl>
#include <QFile>
#include <QDebug>

FtpClient::FtpClient(QObject *parent) : QObject(parent)
{
}

void FtpClient::downloadFiles(const QStringList &urls)
{
    for (const QString &urlStr : urls) {
        QUrl url(urlStr);
        QNetworkRequest request(url);
        QNetworkReply *reply = m_manager.get(request);
        m_replies.append(reply);

        connect(reply, &QNetworkReply::finished, [reply]{
            QString fileName = reply->url().fileName();
            QFile file(fileName);
            if (file.open(QIODevice::WriteOnly)) {
                file.write(reply->readAll());
                file.close();
                qDebug() << "Downloaded" << fileName;
            }
            reply->deleteLater();
        });

        connect(reply, &QNetworkReply::downloadProgress, this, &FtpClient::onDownloadProgress);
    }
}

void FtpClient::onDownloadProgress(qint64 bytesReceived, qint64 bytesTotal)
{
    if (bytesTotal > 0) {
        int progress = (int)(bytesReceived * 100 / bytesTotal);
        qDebug() << "Progress:" << progress << "%";
    }
}

void FtpClient::onDownloadFinished()
{
    QNetworkReply *reply = qobject_cast<QNetworkReply*>(sender());
    m_replies.removeOne(reply);
    if (m_replies.isEmpty()) {
        qDebug() << "All downloads finished";
    }
}
```

使用方式如下：

```cpp
FtpClient client;
QStringList urls;
urls << "ftp://example.com/file1.txt" << "ftp://example.com/file2.txt" << "ftp://example.com/file3.txt";
client.downloadFiles(urls);
```

在这个示例中，我们首先将QNetworkReply*对象存储在一个QList中，然后在所有下载完成后再将其删除。为了实现批量下载的功能，我们需要将要下载的文件的url列表进行封装，然后将其传递给downloadFiles()方法。需要注意的是，由于QNetworkReply对象是异步获取数据的，在下载多个文件时要避免过多的网络请求，以免对带宽和服务器造成不必要的压力。

如果使用上面的示例代码，那么对于每个文件下载都需要重复的进行FTP服务器连接和登陆，这样会影响效率，增加了网络通信的开销。

为了避免重复进行FTP服务器连接和登陆，我们可以采用以下方案：

1. 在FtpClient类构造函数中连接FTP服务器并进行登陆，连接成功后保存连接状态和FTP会话ID；
2. 在下载文件时，每次都使用已经连接的FTP会话ID，以避免重复进行FTP服务器连接和登陆；
3. 在FtpClient类析构函数中，断开连接并释放资源。

具体代码示例如下：

ftpclient.h 文件：

```cpp
#ifndef FTPCLIENT_H
#define FTPCLIENT_H

#include <QObject>
#include <QNetworkAccessManager>
#include <QNetworkReply>

class FtpClient : public QObject
{
    Q_OBJECT
public:
    explicit FtpClient(QObject *parent = nullptr);
    ~FtpClient();
    void downloadFiles(const QStringList &urls);

private:
    QNetworkAccessManager m_manager;
    QList<QNetworkReply*> m_replies;
    bool m_loggedIn = false;
    qint64 m_ftpSessionId;

    bool connectToFtpServer();
    bool loginToFtpServer();

private slots:
    void onDownloadProgress(qint64 bytesReceived, qint64 bytesTotal);
    void onDownloadFinished();
};

#endif // FTPCLIENT_H
```

ftpclient.cpp 文件：

```cpp
#include "ftpclient.h"
#include <QUrl>
#include <QFile>
#include <QDebug>
#include <QNetworkConfigurationManager>

FtpClient::FtpClient(QObject *parent) : QObject(parent)
{
    if (!connectToFtpServer()) {
        qDebug() << "Failed to connect to FTP server";
    }
    else if (!loginToFtpServer()) {
        qDebug() << "Failed to login to FTP server";
    }
    else {
        qDebug() << "Logged in to FTP server";
    }
}

FtpClient::~FtpClient()
{
    if (m_loggedIn) {
        QUrl url("ftp://example.com");
        url.setUserName("");
        url.setPassword("");
        url.setPort(21);
        QNetworkRequest request(url);
        request.setHeader(QNetworkRequest::CommandAttribute, QVariant::fromValue(QNetworkRequest::CustomVerb));
        request.setAttribute(QNetworkRequest::CustomVerbAttribute, "QUIT");
        request.setRawHeader("Connection", "close");
        QNetworkReply *reply = m_manager.post(request, QByteArray());
        reply->waitForFinished();
        delete reply;
    }
}

void FtpClient::downloadFiles(const QStringList &urls)
{
    for (const QString &urlStr : urls) {
        QUrl url(urlStr);
        url.setUserName("");
        url.setPassword("");
        url.setPort(21);
        url.setScheme("ftp");
        url.setUserInfo("");

        QByteArray command("RETR " + url.path().toUtf8());
        QNetworkRequest request(url);
        request.setHeader(QNetworkRequest::ContentTypeHeader, "application/octet-stream");
        request.setRawHeader("Keep-Alive", "timeout=5, max=100");
        request.setAttribute(QNetworkRequest::HttpPipeliningAllowedAttribute, true);
        request.setAttribute(QNetworkRequest::CacheLoadControlAttribute, QNetworkRequest::PreferCache);
        request.setAttribute(QNetworkRequest::CacheSaveControlAttribute, false);
        request.setAttribute(QNetworkRequest::CacheLoadControlAttribute, QNetworkRequest::AlwaysNetwork);
        request.setAttribute(QNetworkRequest::CustomVerbAttribute, command);
        QNetworkReply *reply = m_manager.get(request);
        m_replies.append(reply);

        connect(reply, &QNetworkReply::finished, [reply]{
            QString fileName = reply->url().fileName();
            QFile file(fileName);
            if (file.open(QIODevice::WriteOnly)) {
                file.write(reply->readAll());
                file.close();
                qDebug() << "Downloaded" << fileName;
            }
            reply->deleteLater();
        });

        connect(reply, &QNetworkReply::downloadProgress, this, &FtpClient::onDownloadProgress);
    }
}

bool FtpClient::connectToFtpServer()
{
    QUrl url("ftp://example.com");
    url.setUserName("");
    url.setPassword("");
    url.setPort(21);
    QNetworkRequest request(url);
    QNetworkReply *reply = m_manager.get(request);
    reply->waitForReadyRead();
    QByteArray resp = reply->readLine();
    if (resp.startsWith("220")) {
        bool ok;
        m_ftpSessionId = resp.mid(4).simplified().toLongLong(&ok);
        if (ok) {
            qDebug() << "Connected to FTP server, session ID:" << m_ftpSessionId;
            return true;
        }
    }
    delete reply;
    return false;
}

bool FtpClient::loginToFtpServer()
{
    QUrl url("ftp://example.com");
    url.setUserName("");
    url.setPassword("");
    url.setPort(21);
    QNetworkRequest request(url);
    QByteArray command("USER username");
    request.setAttribute(QNetworkRequest::CustomVerbAttribute, command);
    QNetworkReply *reply = m_manager.get(request);
    reply->waitForReadyRead();
    QByteArray resp = reply->readLine();
    if (resp.startsWith("331")) {
        command = "PASS password";
        request.setAttribute(QNetworkRequest::CustomVerbAttribute, command);
        reply = m_manager.get(request);
        reply->waitForReadyRead();
        resp = reply->readLine();
        if (resp.startsWith("230")) {
            qDebug() << "Logged in to FTP server";
            m_loggedIn = true;
            return true;
        }
    }
    delete reply;
    return false;
}

void FtpClient::onDownloadProgress(qint64 bytesReceived, qint64 bytesTotal)
{
    if (bytesTotal > 0) {
        int progress = (int)(bytesReceived * 100 / bytesTotal);
        qDebug() << "Progress:" << progress << "%";
    }
}

void FtpClient::onDownloadFinished()
{
    QNetworkReply *reply = qobject_cast<QNetworkReply*>(sender());
    m_replies.removeOne(reply);
    if (m_replies.isEmpty()) {
        qDebug() << "All downloads finished";
    }
}
```

在这个示例中，我们首先在FtpClient类构造函数中连接FTP服务器并进行登陆。对于每个文件下载，我们都需要连接已经登录的FTP服务器，并将其SESSION ID作为命令参数传递给FTP服务器，这样我们就无需重复连接和登陆FTP服务器。在FtpClient类析构函数中，我们调用QUIT命令断开与FTP服务器的连接并释放资源。

使用方式与之前的示例相同。

需要注意的是，在使用QNetworkAccessManager进行FTP下载时，网络权限和配置需要进行适当的设置，这在某些平台上可能会涉及到安全和权限问题。例如在Android平台上，需要在AndroidManifest.xml文件中添加以下内容：

```xml
<uses-permission android:name="android.permission.INTERNET"/>
```

使用libcurl实现FTP客户端需要先安装libcurl库，在Ubuntu上可以使用如下命令安装：

```bash
sudo apt-get update
sudo apt-get install libcurl4-openssl-dev
```

安装完成后，可以使用curl_easy_setopt()和curl_easy_perform()等函数来实现FTP文件的上传和下载。下面是使用libcurl实现FTP下载的示例代码：

ftpclient.h文件：

```cpp 
#ifndef FTPCLIENT_H
#define FTPCLIENT_H

#include <QObject>
#include <QByteArray>
#include <QString>
#include <QStringList>
#include <curl/curl.h>

class FtpClient : public QObject
{
    Q_OBJECT
public:
    explicit FtpClient(QObject *parent = nullptr);
    ~FtpClient();
    bool connectToFtpServer(const QString &host, const QString &user, const QString &passwd);
    void disconnectFromFtpServer();
    bool downloadFile(const QString &remotePath, const QString &localPath);
    bool downloadFiles(const QStringList &remotePaths, const QString &localDir);

private:
    CURL *m_curl;
    QByteArray m_buffer;

    static size_t writeFunction(char *ptr, size_t size, size_t nmemb, void *userdata);

    bool performCurlOperation(const QString &url, const QByteArray &postFields = QByteArray(), const struct curl_slist *headers = nullptr);

    void resetBuffer();
    void appendToBuffer(const QByteArray &data);
};

#endif // FTPCLIENT_H
```

ftpclient.cpp文件：

```cpp
#include "ftpclient.h"
#include <QDebug>

FtpClient::FtpClient(QObject *parent) : QObject(parent), m_curl(curl_easy_init())
{
}

FtpClient::~FtpClient()
{
    curl_easy_cleanup(m_curl);
}

bool FtpClient::connectToFtpServer(const QString &host, const QString &user, const QString &passwd)
{
    if (m_curl) {
        QString url = QString("ftp://%1").arg(host);
        curl_easy_setopt(m_curl, CURLOPT_URL, url.toUtf8().constData());
        curl_easy_setopt(m_curl, CURLOPT_USERPWD, QString("%1:%2").arg(user).arg(passwd).toUtf8().constData());
        curl_easy_setopt(m_curl, CURLOPT_FTP_RESPONSE_TIMEOUT, 10L);
        curl_easy_setopt(m_curl, CURLOPT_FTP_USE_EPSV, 1L);
        CURLcode res = curl_easy_perform(m_curl);
        if (res != CURLE_OK) {
            qDebug() << "Failed to connect to FTP server:" << curl_easy_strerror(res);
            return false;
        }
        qDebug() << "Connected to FTP server:" << host;
        return true;
    }
    return false;
}

void FtpClient::disconnectFromFtpServer()
{
    resetBuffer();
}

bool FtpClient::downloadFile(const QString &remotePath, const QString &localPath)
{
    if (m_curl) {
        QFile localFile(localPath);
        if (!localFile.open(QIODevice::WriteOnly)) {
            qDebug() << "Failed to open local file:" << localPath;
            return false;
        }
        resetBuffer();
        QString url = QString("ftp://%1%2").arg(curl_easy_escape(m_curl, remotePath.toUtf8().constData(), remotePath.length())).arg(";type=i");
        curl_easy_setopt(m_curl, CURLOPT_URL, url.toUtf8().constData());
        curl_easy_setopt(m_curl, CURLOPT_WRITEFUNCTION, write
